const { NordicIslandsError } = require('../../error/nordic-islands-error');
const { APP_FILE_MEMBERS } = require('../../constants/file');
const {
  getLookingForIslandsInPageError,
} = require('../../error/get-discovery-error');
const { astCache } = require('../../cache/ast-cache');
const { getImportedComponentsFromFile } = require('./imported-components');
const { getSortedJSXElementsOfComponent } = require('./jsx-elements');
const { getIslands } = require('./islands-of-file');
const { validateIslandsUniqueName } = require('./name-validator');

/**
 * @typedef {import('../../helpers/file-system/islands-manifest').IslandsManifest} IslandsManifest
 */

/**
 * @param { string } filePath
 * @returns { IslandsManifest } Islands
 */
const getIslandsFromPage = (filePath) => {
  try {
    const ast = astCache.getAstByFilePath(filePath);

    const { islandWrapper, importedComponents } = getImportedComponentsFromFile(
      filePath,
      ast,
    );

    if (!Object.keys(importedComponents).length && !islandWrapper) {
      return {};
    }

    const sortedComponents = getSortedJSXElementsOfComponent(ast, filePath, {
      importedComponents,
      islandWrapper,
    });

    const islands = getIslands(sortedComponents, filePath);

    validateIslandsUniqueName(islands);

    return islands;
  } catch (error) {
    throw new NordicIslandsError(
      getLookingForIslandsInPageError(error.message),
      {
        type: APP_FILE_MEMBERS.PAGE,
        path: filePath,
      },
      error,
    );
  }
};

module.exports = { getIslandsFromPage };
